import { describe, expect, it, vi } from "vitest";
import { normalizeTraceIds, readTracesBatched } from "./readTracesBatched.js";
// Deterministic valid UUIDs: padStart keeps the first group 8 hex digits.
const uuid = (n) => `${String(n).padStart(8, "0")}-0000-4000-8000-000000000000`;
const okResult = (text) => ({
    content: [{ type: "text", text }],
});
function fakeClient(call) {
    return {
        ensureSession: vi.fn(async () => { }),
        call: vi.fn(call),
        serviceUrl: "http://test",
    };
}
describe("normalizeTraceIds", () => {
    it("rejects an empty list", () => {
        const result = normalizeTraceIds([]);
        expect(result.ok).toBe(false);
    });
    it("rejects a non-UUID", () => {
        const result = normalizeTraceIds([uuid(1), "not-a-uuid"]);
        expect(result).toEqual({
            ok: false,
            message: "Invalid trace ID (not a UUID): not-a-uuid",
        });
    });
    it("dedupes while preserving first-seen order", () => {
        const result = normalizeTraceIds([uuid(2), uuid(1), uuid(2), uuid(3)]);
        expect(result).toEqual({ ok: true, ids: [uuid(2), uuid(1), uuid(3)] });
    });
});
describe("readTracesBatched", () => {
    it("batches into groups of 10 and concatenates in input order", async () => {
        const ids = Array.from({ length: 25 }, (_, i) => uuid(i));
        const client = fakeClient(async (_tool, args) => {
            const batch = args.traceIds;
            return okResult(`batch:${batch[0]}`);
        });
        const result = await readTracesBatched({
            client,
            traceIds: ids,
            scope: "full",
        });
        expect(result.status).toBe("ok");
        if (result.status !== "ok") {
            return;
        }
        expect(result.traceCount).toBe(25);
        expect(result.batchCount).toBe(3);
        // 3 batches, starting at IDs 0, 10, 20, concatenated in order.
        expect(result.text).toBe([`batch:${uuid(0)}`, `batch:${uuid(10)}`, `batch:${uuid(20)}`].join("\n\n---\n\n"));
        // Each call carries at most 10 IDs and the requested scope.
        for (const call of client.call.mock.calls) {
            const [tool, args] = call;
            expect(tool).toBe("read_traces");
            expect(args.traceIds.length).toBeLessThanOrEqual(10);
            expect(args.scope).toBe("full");
        }
    });
    it("warms the session once before fanning out", async () => {
        const ids = Array.from({ length: 15 }, (_, i) => uuid(i));
        const client = fakeClient(async () => okResult("x"));
        await readTracesBatched({
            client,
            traceIds: ids,
            scope: "summary",
        });
        expect(client.ensureSession).toHaveBeenCalledTimes(1);
    });
    it("preserves order even when later batches resolve first", async () => {
        const ids = Array.from({ length: 30 }, (_, i) => uuid(i));
        const client = fakeClient(async (_tool, args) => {
            const batch = args.traceIds;
            // First batch resolves slowest, so a naive race would reorder output.
            const delay = batch[0] === uuid(0) ? 20 : 1;
            await new Promise((resolve) => setTimeout(resolve, delay));
            return okResult(`batch:${batch[0]}`);
        });
        const result = await readTracesBatched({
            client,
            traceIds: ids,
            scope: "summary",
        });
        expect(result.status).toBe("ok");
        if (result.status !== "ok") {
            return;
        }
        expect(result.text).toBe([`batch:${uuid(0)}`, `batch:${uuid(10)}`, `batch:${uuid(20)}`].join("\n\n---\n\n"));
    });
    it("respects the concurrency cap", async () => {
        const ids = Array.from({ length: 60 }, (_, i) => uuid(i));
        let inFlight = 0;
        let maxInFlight = 0;
        const client = fakeClient(async () => {
            inFlight += 1;
            maxInFlight = Math.max(maxInFlight, inFlight);
            await new Promise((resolve) => setTimeout(resolve, 5));
            inFlight -= 1;
            return okResult("x");
        });
        await readTracesBatched({
            client,
            traceIds: ids,
            scope: "summary",
            concurrency: 2,
        });
        expect(maxInFlight).toBeLessThanOrEqual(2);
        expect(client.call).toHaveBeenCalledTimes(6);
    });
    it("returns mcp-error with the failed batch index", async () => {
        const ids = Array.from({ length: 25 }, (_, i) => uuid(i));
        const client = fakeClient(async (_tool, args) => {
            const batch = args.traceIds;
            if (batch[0] === uuid(10)) {
                return { content: [{ type: "text", text: "boom" }], isError: true };
            }
            return okResult("ok");
        });
        const result = await readTracesBatched({
            client,
            traceIds: ids,
            scope: "full",
        });
        expect(result).toEqual({
            status: "mcp-error",
            message: "boom",
            failedBatchIndex: 1,
        });
    });
    it("rejects invalid input before calling the client", async () => {
        const client = fakeClient(async () => okResult("x"));
        const result = await readTracesBatched({
            client,
            traceIds: ["bad"],
            scope: "summary",
        });
        expect(result.status).toBe("invalid-input");
        expect(client.call).not.toHaveBeenCalled();
    });
    it("dedupes IDs so a duplicate does not read the same trace twice", async () => {
        const client = fakeClient(async () => okResult("x"));
        const result = await readTracesBatched({
            client,
            traceIds: [uuid(1), uuid(1), uuid(2)],
            scope: "summary",
        });
        expect(result.status).toBe("ok");
        if (result.status !== "ok") {
            return;
        }
        expect(result.traceCount).toBe(2);
        const [, args] = client.call.mock.calls[0];
        expect(args.traceIds).toEqual([uuid(1), uuid(2)]);
    });
});
